SELECT COUNT(*) AS pending_requests
FROM adoption_requests
WHERE request_status = 'pending';

SELECT username
FROM users
WHERE user_id IN (
  SELECT user_id
  FROM dog_adoption
);

SELECT request_status
FROM adoption_requests
WHERE user_id = '1';

SELECT username
FROM users
WHERE user_id IN (
  SELECT user_id
  FROM dogs
);

SELECT dog_id, MAX(adoption_date) AS most_recent_adoption_date
FROM dog_adoption
GROUP BY dog_id;

SELECT AVG(rating) AS average_rating
FROM ratings
WHERE dog_id IN (
  SELECT dog_id 
  FROM dog_adoption
);

SELECT adoption_id 
FROM dog_adoption
ORDER BY adoption_date DESC;
